// ===== Common abbreviations =====
let owning_pre: ContainerPtr = pre_self_.get_proc(target_proc_ptr).owning_container;
let shared_addr: PagePtr = pre_self_.get_address_space(src_proc_ptr)[src_va].addr;
let new_entry = pre_self_.get_address_space(src_proc_ptr)[src_va];

// ===== Pull every quantified ensures of run-1 into the proof context =====
// (Re-stating an ensures forces z3 to consider its triggers under the
//  current goal — without this, the two forall ensures from run-1 and
//  run-2 are never instantiated at the same key, and the cross-run
//  pointwise equalities below stay unprovable.)
assert(forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr)
        ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr| #![auto]
    post1_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post1_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));
assert(forall|t_ptr: ThreadPtr| #![auto]
    post1_self_.thread_dom().contains(t_ptr)
        ==> post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|c_ptr: ContainerPtr| #![auto]
    post1_self_.container_dom().contains(c_ptr) && c_ptr != owning_pre
        ==> post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|e_ptr: EndpointPtr| #![auto]
    post1_self_.endpoint_dom().contains(e_ptr)
        ==> post1_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|c: ContainerPtr| #![auto]
    post1_self_.container_dom().contains(c)
        ==> post1_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c));

// ===== Pull every quantified ensures of run-2 into the proof context =====
assert(forall|p_ptr: ProcPtr| #![auto]
    post2_self_.proc_dom().contains(p_ptr)
        ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
assert(forall|p_ptr: ProcPtr| #![auto]
    post2_self_.proc_dom().contains(p_ptr) && p_ptr != target_proc_ptr
        ==> post2_self_.get_address_space(p_ptr) =~= pre_self_.get_address_space(p_ptr));
assert(forall|t_ptr: ThreadPtr| #![auto]
    post2_self_.thread_dom().contains(t_ptr)
        ==> post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
assert(forall|c_ptr: ContainerPtr| #![auto]
    post2_self_.container_dom().contains(c_ptr) && c_ptr != owning_pre
        ==> post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
assert(forall|e_ptr: EndpointPtr| #![auto]
    post2_self_.endpoint_dom().contains(e_ptr)
        ==> post2_self_.get_endpoint(e_ptr) =~= pre_self_.get_endpoint(e_ptr));
assert(forall|c: ContainerPtr| #![auto]
    post2_self_.container_dom().contains(c)
        ==> post2_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c));

// ===== Domains agree (each post-state inherits pre-state's domains) =====
assert(post1_self_.proc_dom()      == pre_self_.proc_dom());
assert(post2_self_.proc_dom()      == pre_self_.proc_dom());
assert(post1_self_.thread_dom()    == pre_self_.thread_dom());
assert(post2_self_.thread_dom()    == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom()  == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom()  == pre_self_.endpoint_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());

// owning_container at target_proc_ptr is also a function of pre-state in
// both runs (because get_proc(target_proc_ptr) is preserved).
assert(post1_self_.get_proc(target_proc_ptr) =~= pre_self_.get_proc(target_proc_ptr));
assert(post2_self_.get_proc(target_proc_ptr) =~= pre_self_.get_proc(target_proc_ptr));
assert(post1_self_.get_proc(target_proc_ptr).owning_container == owning_pre);
assert(post2_self_.get_proc(target_proc_ptr).owning_container == owning_pre);

// ===== Target proc's address-space is fully determined by the pre-state =====
assert(post1_self_.get_address_space(target_proc_ptr) =~=
    pre_self_.get_address_space(target_proc_ptr).insert(target_va, new_entry));
assert(post2_self_.get_address_space(target_proc_ptr) =~=
    pre_self_.get_address_space(target_proc_ptr).insert(target_va, new_entry));
assert(post1_self_.get_address_space(target_proc_ptr)
    =~= post2_self_.get_address_space(target_proc_ptr));

// Cross-run pointwise equality on address-spaces (case-split on target).
assert forall|p_ptr: ProcPtr| post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_address_space(p_ptr)
            =~= post2_self_.get_address_space(p_ptr) by {
    if p_ptr == target_proc_ptr {
        // Both equal pre.get_address_space(target_proc_ptr).insert(target_va, new_entry).
    } else {
        // Both equal pre.get_address_space(p_ptr).
    }
};

// Cross-run pointwise equality on procs / threads / endpoints / owned-pages.
assert forall|p_ptr: ProcPtr| post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {};
assert forall|t_ptr: ThreadPtr| post1_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {};
assert forall|e_ptr: EndpointPtr| post1_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {};
assert forall|c: ContainerPtr| post1_self_.container_dom().contains(c)
    implies post1_self_.get_container_owned_pages(c)
            =~= post2_self_.get_container_owned_pages(c) by {};

// Cross-run pointwise equality on containers (case-split on owning_pre).
assert forall|c_ptr: ContainerPtr| post1_self_.container_dom().contains(c_ptr)
        && c_ptr != owning_pre
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {};

// ===== page_mapping: domains equal, and both runs agree pointwise =====
assert(post1_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom());
assert(post2_self_.page_mapping@.dom() == pre_self_.page_mapping@.dom());
assert(post1_self_.page_mapping@.dom() == post2_self_.page_mapping@.dom());

assert(post1_self_.page_mapping@[shared_addr]
    == pre_self_.page_mapping@[shared_addr].insert((target_proc_ptr, target_va)));
assert(post2_self_.page_mapping@[shared_addr]
    == pre_self_.page_mapping@[shared_addr].insert((target_proc_ptr, target_va)));

assert(forall|page_ptr: PagePtr| #![trigger post1_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != shared_addr
        ==> pre_self_.page_mapping@[page_ptr] == post1_self_.page_mapping@[page_ptr]);
assert(forall|page_ptr: PagePtr| #![trigger post2_self_.page_mapping@[page_ptr]]
    pre_self_.page_mapping@.dom().contains(page_ptr) && page_ptr != shared_addr
        ==> pre_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr]);

assert forall|page_ptr: PagePtr| post1_self_.page_mapping@.dom().contains(page_ptr)
    implies post1_self_.page_mapping@[page_ptr] == post2_self_.page_mapping@[page_ptr] by {
    if page_ptr == shared_addr {
        // Both equal pre.page_mapping@[shared_addr].insert((target_proc_ptr, target_va)).
    } else {
        // Both equal pre.page_mapping@[page_ptr] (uses preservation forall).
    }
};
assert(post1_self_.page_mapping@ =~= post2_self_.page_mapping@);

// ===== page_alloc.page_is_mapped preserved by both runs =====
assert(forall|p: PagePtr| #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));
assert(forall|p: PagePtr| #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) == pre_self_.page_alloc.page_is_mapped(p));

// ===== Physical-page reference counter: only shared_addr changes (+1) =====
assert(pre_self_.get_physical_page_reference_counter(shared_addr) + 1
    == post1_self_.get_physical_page_reference_counter(shared_addr));
assert(pre_self_.get_physical_page_reference_counter(shared_addr) + 1
    == post2_self_.get_physical_page_reference_counter(shared_addr));
assert(post1_self_.get_physical_page_reference_counter(shared_addr)
    == post2_self_.get_physical_page_reference_counter(shared_addr));

assert(forall|p: PagePtr| #![trigger post1_self_.page_alloc.page_is_mapped(p)]
    post1_self_.page_alloc.page_is_mapped(p) && p != shared_addr
        ==> pre_self_.get_physical_page_reference_counter(p)
            == post1_self_.get_physical_page_reference_counter(p));
assert(forall|p: PagePtr| #![trigger post2_self_.page_alloc.page_is_mapped(p)]
    post2_self_.page_alloc.page_is_mapped(p) && p != shared_addr
        ==> pre_self_.get_physical_page_reference_counter(p)
            == post2_self_.get_physical_page_reference_counter(p));

// ===== num_of_free_pages: both runs subtract the same return amount from pre =====
assert(post1_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - r1);
assert(post2_self_.get_num_of_free_pages() == pre_self_.get_num_of_free_pages() - r2);

// ===== Quota subtraction: both runs satisfy spec_subtract_mem_4k from the same pre-quota =====
assert(pre_self_.get_container(owning_pre).quota.spec_subtract_mem_4k(
    post1_self_.get_container(owning_pre).quota, r1));
assert(pre_self_.get_container(owning_pre).quota.spec_subtract_mem_4k(
    post2_self_.get_container(owning_pre).quota, r2));

// ===== Preserved fields of the owning_pre container in both runs =====
assert(post1_self_.get_container(owning_pre).owned_procs
    =~= pre_self_.get_container(owning_pre).owned_procs);
assert(post2_self_.get_container(owning_pre).owned_procs
    =~= pre_self_.get_container(owning_pre).owned_procs);
assert(post1_self_.get_container(owning_pre).parent
    =~= pre_self_.get_container(owning_pre).parent);
assert(post2_self_.get_container(owning_pre).parent
    =~= pre_self_.get_container(owning_pre).parent);
assert(post1_self_.get_container(owning_pre).parent_rev_ptr
    =~= pre_self_.get_container(owning_pre).parent_rev_ptr);
assert(post2_self_.get_container(owning_pre).parent_rev_ptr
    =~= pre_self_.get_container(owning_pre).parent_rev_ptr);
assert(post1_self_.get_container(owning_pre).children
    =~= pre_self_.get_container(owning_pre).children);
assert(post2_self_.get_container(owning_pre).children
    =~= pre_self_.get_container(owning_pre).children);
assert(post1_self_.get_container(owning_pre).owned_endpoints
    =~= pre_self_.get_container(owning_pre).owned_endpoints);
assert(post2_self_.get_container(owning_pre).owned_endpoints
    =~= pre_self_.get_container(owning_pre).owned_endpoints);
assert(post1_self_.get_container(owning_pre).owned_threads
    =~= pre_self_.get_container(owning_pre).owned_threads);
assert(post2_self_.get_container(owning_pre).owned_threads
    =~= pre_self_.get_container(owning_pre).owned_threads);
assert(post1_self_.get_container(owning_pre).owned_cpus
    =~= pre_self_.get_container(owning_pre).owned_cpus);
assert(post2_self_.get_container(owning_pre).owned_cpus
    =~= pre_self_.get_container(owning_pre).owned_cpus);
assert(post1_self_.get_container(owning_pre).scheduler
    =~= pre_self_.get_container(owning_pre).scheduler);
assert(post2_self_.get_container(owning_pre).scheduler
    =~= pre_self_.get_container(owning_pre).scheduler);
